using System.ComponentModel.DataAnnotations;

namespace sv_9ae13d943d6745e2bac09660b8319782.Components.Pages;

public class AppointmentModel
{
    [Required(ErrorMessage = "Patient name is required")]
    public string PatientName { get; set; } = "";

    [Required(ErrorMessage = "Email is required")]
    [EmailAddress(ErrorMessage = "Invalid email format")]
    public string Email { get; set; } = "";

    [Required(ErrorMessage = "Phone is required")]
    public string Phone { get; set; } = "";

    [Required(ErrorMessage = "Insurance provider is required")]
    public string InsuranceProvider { get; set; } = "";

    [Required(ErrorMessage = "Doctor selection is required")]
    public string Doctor { get; set; } = "";

    [Required(ErrorMessage = "Date is required")]
    [FutureDate(ErrorMessage = "Date must be in the future")]
    public DateTime? AppointmentDate { get; set; }

    [Required(ErrorMessage = "Time slot is required")]
    public string TimeSlot { get; set; } = "";

    [Required(ErrorMessage = "Reason for visit is required")]
    [MaxLength(500, ErrorMessage = "Reason must be 500 characters or fewer")]
    public string ReasonForVisit { get; set; } = "";
}

public class FutureDateAttribute : ValidationAttribute
{
    protected override ValidationResult? IsValid(object? value, ValidationContext validationContext)
    {
        if (value is DateTime date && date.Date <= DateTime.Today)
        {
            return new ValidationResult(ErrorMessage);
        }
        return ValidationResult.Success;
    }
}

